        tariff = getTariffType(timeVal: r._time)
        return {r with _value: r._value * getPrice(tariffName: tariff), tariff: tariff}
    })
    |> group(columns: ["tariff"])
    |> sum()
    |> group()
    |> sort(columns: ["_value"], desc: true)

